const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;

function firstPresent(...values) {
  return values.find(value => value !== undefined && value !== null && value !== "");
}

function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null || value === "") return [];
  return [value];
}

function compactArray(value) {
  return asArray(value).filter(item => item !== undefined && item !== null && item !== "");
}

function numberOrNull(value) {
  if (value === undefined || value === null || value === "") return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function hasAny(text, terms) {
  const t = String(text || "").toLowerCase();
  return terms.some(term => t.includes(String(term).toLowerCase()));
}

function inferTimeFromText(text) {
  const t = String(text || "");
  const result = {};

  const dayMatch = t.match(/(?:days_left|daysLeft|day|days)\D{0,8}(\d{1,3})/i)
    || t.match(/(\d{1,3})\s*(?:day|days)/i)
    || t.match(/(\d{1,3})\s*\u5929/u);

  const hourPerDayMatch = t.match(/(?:hours_per_day|hoursPerDay)\D{0,8}(\d{1,3})/i)
    || t.match(/(?:every day|per day|daily)\D{0,12}(\d{1,3})\s*(?:hour|hours|h)/i)
    || t.match(/(?:\u6bcf\u5929|\u6bcf\u65e5|\u4e00\u5929)\D{0,12}(\d{1,3})\s*(?:\u5c0f\u65f6|h)/u)
    || t.match(/(\d{1,3})\s*(?:\u5c0f\u65f6|h)\D{0,12}(?:\u6bcf\u5929|\u6bcf\u65e5|\u4e00\u5929)/u);

  const totalHourMatch = t.match(/(?:total_hours|totalHours|estimated_total_hours|estimatedTotalHours)\D{0,8}(\d{1,3})/i)
    || t.match(/(?:total|overall)\D{0,12}(\d{1,3})\s*(?:hour|hours|h)/i)
    || t.match(/(?:\u603b\u5171|\u4e00\u5171|\u603b\u8ba1)\D{0,12}(\d{1,3})\s*(?:\u5c0f\u65f6|h)/u);

  if (dayMatch) result.days_left = Number(dayMatch[1]);
  if (hourPerDayMatch) result.hours_per_day = Number(hourPerDayMatch[1]);
  if (totalHourMatch) result.estimated_total_hours = Number(totalHourMatch[1]);
  if (result.estimated_total_hours === undefined && result.days_left !== undefined && result.hours_per_day !== undefined) {
    result.estimated_total_hours = result.days_left * result.hours_per_day;
  }
  return result;
}

function inferPreferredFocus(text) {
  const focus = [];
  if (hasAny(text, ["calculation", "compute", "numerical", "formula", "sigmoid", "\u8ba1\u7b97", "\u4ee3\u5165", "\u516c\u5f0f"])) focus.push("calculation");
  if (hasAny(text, ["concept", "understanding", "definition", "short answer", "\u6982\u5ff5", "\u7406\u89e3", "\u5b9a\u4e49", "\u7b80\u7b54"])) focus.push("understanding");
  if (hasAny(text, ["application", "problem", "practice", "\u5e94\u7528", "\u9898\u76ee", "\u505a\u9898"])) focus.push("application");
  if (hasAny(text, ["derive", "derivation", "proof", "\u8bc1\u660e", "\u63a8\u5bfc"])) focus.push("derivation");
  if (hasAny(text, ["program", "coding", "implementation", "\u7f16\u7a0b", "\u4ee3\u7801", "\u5b9e\u73b0"])) focus.push("implementation");
  return [...new Set(focus)];
}

function inferPreferredOutput(text) {
  const output = [];
  if (hasAny(text, ["schedule", "plan", "daily", "\u8ba1\u5212", "\u5b89\u6392", "\u65e5\u7a0b", "\u6bcf\u5929"])) output.push("daily_schedule");
  if (hasAny(text, ["checklist", "list", "\u6e05\u5355", "\u5217\u8868"])) output.push("priority_checklist");
  if (hasAny(text, ["priority", "focus", "\u91cd\u70b9", "\u4f18\u5148"])) output.push("priority_focus");
  return [...new Set(output.length ? output : ["priority_checklist"] )];
}

function inferGoal(text) {
  if (hasAny(text, ["schedule", "plan", "how to review", "\u8ba1\u5212", "\u5b89\u6392", "\u600e\u4e48\u590d\u4e60"])) return "review_planning";
  if (hasAny(text, ["priority", "focus", "high frequency", "\u91cd\u70b9", "\u4f18\u5148", "\u9ad8\u9891"])) return "priority_focus";
  if (hasAny(text, ["score", "grade", "\u63d0\u5206", "\u5206\u6570", "\u6210\u7ee9"])) return "score_improvement";
  return "course_review";
}

const userMessage = firstPresent(body.user_message, body.userMessage, body.message, body.raw_request, body.rawRequest, body.text, "");
const directTime = firstPresent(body.time_constraints, body.timeConstraints, body.available_time, body.availableTime, {});
const inferredTime = inferTimeFromText(userMessage);
const daysLeft = numberOrNull(firstPresent(directTime.days_left, directTime.daysLeft, body.days_left, body.daysLeft, inferredTime.days_left));
const hoursPerDay = numberOrNull(firstPresent(directTime.hours_per_day, directTime.hoursPerDay, body.hours_per_day, body.hoursPerDay, inferredTime.hours_per_day));
const explicitTotal = numberOrNull(firstPresent(directTime.estimated_total_hours, directTime.estimatedTotalHours, directTime.total_hours, directTime.totalHours, body.estimated_total_hours, body.estimatedTotalHours, inferredTime.estimated_total_hours));
const estimatedTotal = explicitTotal ?? ((daysLeft !== null && hoursPerDay !== null) ? daysLeft * hoursPerDay : null);

const courseId = firstPresent(body.course_id, body.courseId, "course_unknown");
const courseName = firstPresent(body.course_name, body.courseName, "Unknown Course");
const studentId = firstPresent(body.student_id, body.studentId, "student_unknown");
const agentBaseUrl = String(firstPresent(body.agent_base_url, body.agentBaseUrl, "http://localhost:5678/webhook")).replace(/\/$/, "");

const materials = compactArray(firstPresent(body.materials, body.course_materials, body.courseMaterials, []));
const lectures = [
  ...compactArray(firstPresent(body.lectures, [])),
  ...compactArray(firstPresent(body.lecture_notes, body.lectureNotes, [])),
  ...compactArray(firstPresent(body.transcripts, [])),
  ...compactArray(firstPresent(body.notes, []))
];
const pastExams = [
  ...compactArray(firstPresent(body.past_exams, body.pastExams, [])),
  ...compactArray(firstPresent(body.exam_sets, body.examSets, []))
];
const questions = [
  ...compactArray(firstPresent(body.questions, [])),
  ...compactArray(firstPresent(body.exam_questions, body.examQuestions, []))
];
const studentInputs = [
  ...compactArray(firstPresent(body.student_inputs, body.studentInputs, [])),
  ...compactArray(firstPresent(body.self_assessments, body.selfAssessments, []))
];
const mistakeRecords = [
  ...compactArray(firstPresent(body.mistake_records, body.mistakeRecords, [])),
  ...compactArray(firstPresent(body.wrong_questions, body.wrongQuestions, [])),
  ...compactArray(firstPresent(body.mistakes, []))
];

const userReviewRequestInput = firstPresent(body.user_review_request, body.userReviewRequest, body.review_request, body.reviewRequest, {});
const preferredFocus = compactArray(firstPresent(userReviewRequestInput.preferred_focus, userReviewRequestInput.preferredFocus, body.preferred_focus, body.preferredFocus, inferPreferredFocus(userMessage)));
const preferredOutput = compactArray(firstPresent(userReviewRequestInput.preferred_output, userReviewRequestInput.preferredOutput, body.preferred_output, body.preferredOutput, inferPreferredOutput(userMessage)));
const strategyOptionsInput = firstPresent(body.strategy_options, body.strategyOptions, {});

const userReviewRequest = {
  raw_request: firstPresent(userReviewRequestInput.raw_request, userReviewRequestInput.rawRequest, userReviewRequestInput.text, userMessage, ""),
  goal: firstPresent(userReviewRequestInput.goal, body.goal, inferGoal(userMessage)),
  target_level: firstPresent(userReviewRequestInput.target_level, userReviewRequestInput.targetLevel, userReviewRequestInput.target_score, userReviewRequestInput.targetScore, body.target_level, body.targetLevel, body.target_score, body.targetScore, null),
  available_time: {
    days_left: daysLeft,
    hours_per_day: hoursPerDay,
    estimated_total_hours: estimatedTotal
  },
  preferred_focus: preferredFocus,
  preferred_output: preferredOutput,
  constraints: compactArray(firstPresent(userReviewRequestInput.constraints, body.constraints, [])),
  language: firstPresent(userReviewRequestInput.language, strategyOptionsInput.language, body.language, "zh")
};

const strategyOptions = {
  planning_style: firstPresent(strategyOptionsInput.planning_style, strategyOptionsInput.planningStyle, "time_boxed"),
  risk_tolerance: firstPresent(strategyOptionsInput.risk_tolerance, strategyOptionsInput.riskTolerance, "conservative"),
  max_focus_items: numberOrNull(firstPresent(strategyOptionsInput.max_focus_items, strategyOptionsInput.maxFocusItems, 8)),
  include_daily_plan: firstPresent(strategyOptionsInput.include_daily_plan, strategyOptionsInput.includeDailyPlan, preferredOutput.includes("daily_schedule")),
  include_low_confidence_items: firstPresent(strategyOptionsInput.include_low_confidence_items, strategyOptionsInput.includeLowConfidenceItems, true),
  include_checklist: firstPresent(strategyOptionsInput.include_checklist, strategyOptionsInput.includeChecklist, preferredOutput.includes("priority_checklist")),
  language: userReviewRequest.language
};

return [{
  json: {
    workflow_name: "courselens_orchestrator",
    course_id: courseId,
    course_name: courseName,
    student_id: studentId,
    user_message: userMessage,
    materials,
    lectures,
    past_exams: pastExams,
    questions,
    student_inputs: studentInputs,
    mistake_records: mistakeRecords,
    student_text: firstPresent(body.student_text, body.studentText, ""),
    time_constraints: {
      days_left: daysLeft,
      hours_per_day: hoursPerDay,
      estimated_total_hours: estimatedTotal,
      deadline: firstPresent(directTime.deadline, body.deadline, null)
    },
    user_review_request: userReviewRequest,
    strategy_options: strategyOptions,
    orchestrator_config: {
      agent_base_url: agentBaseUrl,
      include_debug_outputs: Boolean(firstPresent(body.include_debug_outputs, body.includeDebugOutputs, false)),
      fusion_options: firstPresent(body.fusion_options, body.fusionOptions, {
        max_focus_candidates: 10,
        allow_low_evidence_candidates: true
      })
    }
  }
}];

const data = $input.first().json;

function hasTextItems(items) {
  return Array.isArray(items) && items.some(item => {
    if (typeof item === "string") return item.trim().length > 0;
    return Boolean(item?.text || item?.content || item?.question_text || item?.questionText || item?.description);
  });
}

function hasObjectValues(obj) {
  return obj && typeof obj === "object" && Object.values(obj).some(value => value !== null && value !== undefined && value !== "");
}

function hasAny(text, terms) {
  const t = String(text || "").toLowerCase();
  return terms.some(term => t.includes(String(term).toLowerCase()));
}

const studentSignalText = [data.user_message, data.student_text].filter(Boolean).join(" ");
const hasStudentSignal = hasTextItems(data.student_inputs)
  || hasTextItems(data.mistake_records)
  || hasObjectValues(data.time_constraints)
  || hasAny(studentSignalText, [
    "mistake", "weak", "goal", "exam", "review", "hour", "day", "score",
    "\u6211", "\u4e0d\u4f1a", "\u4e0d\u61c2", "\u9519", "\u8584\u5f31", "\u76ee\u6807", "\u5206", "\u8003\u8bd5", "\u590d\u4e60", "\u5929", "\u5c0f\u65f6"
  ]);

const shouldCall = {
  course_material_agent: hasTextItems(data.materials),
  lecture_signal_agent: hasTextItems(data.lectures),
  exam_pattern_agent: hasTextItems(data.past_exams) || hasTextItems(data.questions),
  student_profile_agent: hasStudentSignal
};

const agentReasons = {
  course_material_agent: shouldCall.course_material_agent ? "Course material text was provided." : "No course materials were provided.",
  lecture_signal_agent: shouldCall.lecture_signal_agent ? "Lecture notes or transcripts were provided." : "No lecture notes or transcripts were provided.",
  exam_pattern_agent: shouldCall.exam_pattern_agent ? "Past exams, exam sets, or questions were provided." : "No past exams, exam sets, or questions were provided.",
  student_profile_agent: shouldCall.student_profile_agent ? "Student request, self-assessment, mistakes, target, or time constraints were provided." : "No student profile signals were provided."
};

const calledAgents = Object.entries(shouldCall).filter(([, yes]) => yes).map(([name]) => name);
const skippedAgents = Object.entries(shouldCall)
  .filter(([, yes]) => !yes)
  .map(([agent_name]) => ({ agent_name, reason: agentReasons[agent_name] }));

const warnings = [];
if (!shouldCall.course_material_agent && !shouldCall.exam_pattern_agent && !shouldCall.lecture_signal_agent) {
  warnings.push("No course-side evidence was provided. Any final review advice must be treated as low-evidence and should request course materials, lecture notes, or past exams.");
}
if (!shouldCall.student_profile_agent) {
  warnings.push("No student-specific evidence was provided, so personalization will be limited.");
}

return [{
  json: {
    ...data,
    routing_plan: {
      should_call: shouldCall,
      called_agents: calledAgents,
      skipped_agents: skippedAgents,
      agent_reasons: agentReasons,
      no_upstream_calls: calledAgents.length === 0
    },
    evidence_coverage: {
      has_course_materials: shouldCall.course_material_agent,
      has_lecture_signals: shouldCall.lecture_signal_agent,
      has_exam_patterns: shouldCall.exam_pattern_agent,
      has_student_profile: shouldCall.student_profile_agent
    },
    orchestrator_warnings: warnings
  }
}];

const data = $input.first().json;
const base = data.orchestrator_config.agent_base_url;
const requests = [];

function url(path) {
  return `${base}/${path}`;
}

if (data.routing_plan.should_call.course_material_agent) {
  requests.push({
    agent_name: "course_material_agent",
    agent_url: url("course-material-agent"),
    request_body: {
      course_id: data.course_id,
      course_name: data.course_name,
      materials: data.materials
    }
  });
}

if (data.routing_plan.should_call.lecture_signal_agent) {
  requests.push({
    agent_name: "lecture_signal_agent",
    agent_url: url("lecture-signal-agent"),
    request_body: {
      course_id: data.course_id,
      course_name: data.course_name,
      lectures: data.lectures
    }
  });
}

if (data.routing_plan.should_call.exam_pattern_agent) {
  requests.push({
    agent_name: "exam_pattern_agent",
    agent_url: url("exam-pattern-agent"),
    request_body: {
      course_id: data.course_id,
      course_name: data.course_name,
      past_exams: data.past_exams,
      questions: data.questions
    }
  });
}

if (data.routing_plan.should_call.student_profile_agent) {
  requests.push({
    agent_name: "student_profile_agent",
    agent_url: url("student-profile-agent"),
    request_body: {
      course_id: data.course_id,
      course_name: data.course_name,
      student_id: data.student_id,
      student_inputs: data.student_inputs,
      mistake_records: data.mistake_records,
      student_text: data.student_text || data.user_message || "",
      time_constraints: data.time_constraints,
      target_level: data.user_review_request.target_level
    }
  });
}

if (!requests.length) {
  return [{
    json: {
      skip_all: true,
      reason: "No routable upstream evidence or student signal was provided."
    }
  }];
}

return requests.map(request => ({ json: request }));

const context = $("Build Routing Plan").first().json;
const requestItems = $("Build Upstream Agent Requests").all()
  .map(item => item.json)
  .filter(item => !item.skip_all);
const responseItems = $input.all().map(item => item.json);

const outputsByAgent = {};
const warnings = [...(context.orchestrator_warnings || [])];

for (let i = 0; i < requestItems.length; i++) {
  const request = requestItems[i];
  const response = responseItems[i] ?? {};
  const hasError = Boolean(response.error || response.message?.includes?.("ECONN") || response.statusCode >= 400);
  const output = hasError ? null : response;
  outputsByAgent[request.agent_name] = {
    agent_name: request.agent_name,
    status: hasError ? "failed" : "available",
    reason: hasError ? (response.error?.message || response.message || "The upstream workflow call failed.") : "Upstream workflow returned a response.",
    output
  };
  if (hasError) warnings.push(`${request.agent_name} failed and will be treated as missing evidence.`);
}

for (const skipped of context.routing_plan.skipped_agents || []) {
  outputsByAgent[skipped.agent_name] = {
    agent_name: skipped.agent_name,
    status: "not_provided",
    reason: skipped.reason,
    output: null
  };
}

const fixedOrder = ["course_material_agent", "lecture_signal_agent", "exam_pattern_agent", "student_profile_agent"];
const availableAgentOutputs = fixedOrder.map(agentName => outputsByAgent[agentName] || {
  agent_name: agentName,
  status: "not_provided",
  reason: "No input was routed to this agent.",
  output: null
});

return [{
  json: {
    workflow_name: "courselens_orchestrator",
    course_id: context.course_id,
    course_name: context.course_name,
    student_id: context.student_id,
    user_review_request: context.user_review_request,
    strategy_options: context.strategy_options,
    orchestrator_config: context.orchestrator_config,
    routing_summary: {
      called_agents: context.routing_plan.called_agents,
      skipped_agents: context.routing_plan.skipped_agents,
      upstream_status: availableAgentOutputs.map(item => ({
        agent_name: item.agent_name,
        status: item.status,
        reason: item.reason
      }))
    },
    evidence_coverage: context.evidence_coverage,
    available_agent_outputs: availableAgentOutputs,
    orchestrator_warnings: warnings
  }
}];

const data = $input.first().json;
const requestBody = {
  course_id: data.course_id,
  course_name: data.course_name,
  student_id: data.student_id,
  available_agent_outputs: data.available_agent_outputs,
  fusion_options: data.orchestrator_config.fusion_options || {
    max_focus_candidates: 10,
    allow_low_evidence_candidates: true
  }
};

return [{
  json: {
    ...data,
    fusion_url: `${data.orchestrator_config.agent_base_url}/evidence-fusion-agent`,
    request_body: requestBody
  }
}];

const fusionOutput = $input.first().json;
const context = $("Collect Upstream Agent Outputs").first().json;
const studentProfileEntry = (context.available_agent_outputs || []).find(item => item.agent_name === "student_profile_agent");
const fusionFailed = Boolean(fusionOutput.error || fusionOutput.statusCode >= 400 || fusionOutput.parser_error);

if (fusionFailed) {
  return [{
    json: {
      skip_strategy: true,
      workflow_name: "courselens_orchestrator",
      course_id: context.course_id,
      course_name: context.course_name,
      student_id: context.student_id,
      routing_summary: context.routing_summary,
      evidence_coverage: context.evidence_coverage,
      final_report: null,
      status: "evidence_fusion_failed",
      orchestrator_warnings: [
        ...(context.orchestrator_warnings || []),
        "Evidence Fusion Agent failed, so the orchestrator did not call the final Review Strategy / Critic Agent."
      ],
      error_detail: fusionOutput
    }
  }];
}

const requestBody = {
  course_id: context.course_id,
  course_name: context.course_name,
  student_id: context.student_id,
  user_review_request: context.user_review_request,
  evidence_fusion_map: fusionOutput,
  student_profile_map: studentProfileEntry?.status === "available" ? (studentProfileEntry.output || {}) : {},
  strategy_options: context.strategy_options
};

return [{
  json: {
    workflow_name: "courselens_orchestrator",
    course_id: context.course_id,
    course_name: context.course_name,
    student_id: context.student_id,
    strategy_url: `${context.orchestrator_config.agent_base_url}/review-strategy-critic-agent`,
    request_body: requestBody,
    routing_summary: context.routing_summary,
    evidence_coverage: context.evidence_coverage,
    orchestrator_warnings: context.orchestrator_warnings,
    evidence_fusion_map: fusionOutput,
    available_agent_outputs: context.available_agent_outputs,
    orchestrator_config: context.orchestrator_config
  }
}];

const input = $input.first().json;

if (input.skip_strategy || input.status === "evidence_fusion_failed") {
  return [{ json: input }];
}

const strategyContext = $("Build Strategy Request").first().json;
const strategyOutput = input;
const strategyFailed = Boolean(strategyOutput.error || strategyOutput.statusCode >= 400 || strategyOutput.parser_error);
const warnings = [...(strategyContext.orchestrator_warnings || [])];
if (strategyFailed) warnings.push("Review Strategy / Critic Agent failed, so no final student-facing report was produced.");

const response = {
  workflow_name: "courselens_orchestrator",
  course_id: strategyContext.course_id,
  course_name: strategyContext.course_name,
  student_id: strategyContext.student_id,
  status: strategyFailed ? "review_strategy_failed" : "completed",
  routing_summary: {
    ...strategyContext.routing_summary,
    called_agents: [
      ...(strategyContext.routing_summary.called_agents || []),
      "evidence_fusion_agent",
      ...(strategyFailed ? [] : ["review_strategy_critic_agent"])
    ]
  },
  evidence_coverage: strategyContext.evidence_coverage,
  final_report: strategyFailed ? null : strategyOutput,
  orchestrator_warnings: warnings
};

if (strategyContext.orchestrator_config.include_debug_outputs) {
  response.intermediate_outputs = {
    available_agent_outputs: strategyContext.available_agent_outputs,
    evidence_fusion_map: strategyContext.evidence_fusion_map
  };
}

if (strategyFailed) response.error_detail = strategyOutput;

return [{ json: response }];

const context = $("Build Routing Plan").first().json;
return [{
  json: {
    workflow_name: "courselens_orchestrator",
    course_id: context.course_id,
    course_name: context.course_name,
    student_id: context.student_id,
    status: "insufficient_input",
    routing_summary: {
      called_agents: [],
      skipped_agents: context.routing_plan.skipped_agents
    },
    evidence_coverage: context.evidence_coverage,
    final_report: null,
    missing_input_requests: [
      "Please provide extracted course material text, lecture notes/transcripts, past exams/questions, or student self-assessment/mistake records.",
      "The orchestrator does not parse raw PDF/PPT/audio files in this MVP workflow. Use an ingestion workflow first, then pass extracted text fields here."
    ],
    orchestrator_warnings: [
      ...(context.orchestrator_warnings || []),
      "No upstream agent was called because no routable input was found."
    ]
  }
}];
